122		}
123		if def.ID == "" {
124			return nil, nil, fmt.Errorf("exec definition is missing id")
125		}
126		if len(def.ArtifactIDs) == 0 {
127			return nil, nil, fmt.Errorf("exec definition %q has no artifact_ids", def.ID)
128		}
129		if def.Executor.Kind != ExecutorKindCommand && def.Executor.Kind != ExecutorKindAgent {
130			return nil, nil, fmt.Errorf("exec definition %q has invalid executor kind %q", def.ID, def.Executor.Kind)
131		}
132		if def.Executor.Kind == ExecutorKindCommand && len(def.Executor.Command) == 0 {
133			return nil, nil, fmt.Errorf("exec definition %q has no command", def.ID)
134		}
135		if graph == nil {
136			graph, err = s.buildGraph()
137			if err != nil {
138				return nil, nil, err
139			}
140		}
141		var primary *docgraph.Document
142		for _, artifactID := range def.ArtifactIDs {
143			doc, ok := graph.Show(artifactID)
144			if !ok {
145				return nil, nil, fmt.Errorf("exec definition %q references missing artifact %q", def.ID, artifactID)
146			}
147			if primary == nil {
148				docCopy := doc
149				primary = &docCopy
150			}
151		}
152		return &def, primary, nil
153	}
